targets.expr:
( # Classic storage
  sum by (cluster, namespace, ) (
    cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
- (
    cortex_ingester_active_native_histogram_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
    or cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"} * 0
  )
+ (
    cortex_ingester_active_native_histogram_buckets{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
    or cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"} * 0
  ) / 4
 unless on (job)
    cortex_partition_ring_partitions{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
  )
  / on (cluster, namespace) group_left()
  max by (cluster, namespace) (cortex_distributor_replication_factor{cluster=~"$cluster", job=~"($namespace)/((distributor.*|cortex|mimir))"})
)
or
( # Ingest storage
  sum by (cluster, namespace, ) (
    max by (ingester_id, cluster, namespace, ) (
      label_replace(
        cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
- (
    cortex_ingester_active_native_histogram_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
    or cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"} * 0
  )
+ (
    cortex_ingester_active_native_histogram_buckets{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"}
    or cortex_ingester_active_series{cluster=~"$cluster", job=~"($namespace)/((ingester.*|cortex|mimir))"} * 0
  ) / 4
,
        "ingester_id", "$1", "instance", ".*-([0-9]+)$"
      )
    )
  )
)

